# Map Supabase `categories.categoryid` -> default prompt for that garment type.
# Categories without a tailored prompt yet are simply absent (handled by callers).
CATEGORY_PROMPTS: dict[str, str] = {
    "SA": SAREE_PROMPT,
    "KP": KURTA_PAJAMA_PROMPT,
    "C-KP": KURTA_PAJAMA_CHILD_PROMPT,
    "GWN": GOWN_PROMPT,
    "LE": LEHENGA_PROMPT,
    "SHT": MEN_SHIRT_PROMPT,
    "KUR": KURTI_PROMPT,
    "NHJ": NEHRU_JACKET_PROMPT,
    "SKT-TOP": SKIRT_CROP_TOP_PROMPT,
    "CRD": CORD_SET_PROMPT,
    "TOP": WOMEN_TOP,
}


def prompt_for_category(categoryid: str) -> str | None:
    """Return the default prompt for a category id, or None if none defined."""
    return CATEGORY_PROMPTS.get(categoryid)
